276								setRef(e.target.value);
277								if (error) setError(null);
278							}}
279							className="mono ml-3 flex-1 bg-transparent text-[13px] text-[var(--color-text)] outline-none placeholder:text-[var(--color-text-dim)]"
280						/>
281					</div>
282					{error ? (
283						<div
284							role="alert"
285							className="text-[12px] text-[var(--color-red)] leading-[1.4]"
286						>
287							{error}
288						</div>
289					) : null}
290				</div>
291	
292				<div className="flex items-center gap-4">
293					<button
294						type="submit"
295						disabled={submitting || !brandReady}
296						className="inline-flex h-11 w-[240px] items-center justify-center gap-2 rounded-md border border-[var(--color-magenta)] bg-[var(--color-magenta)] px-4 font-medium text-[14px] text-white transition-[background-color,transform,opacity] duration-[120ms] hover:bg-[#ED2F86] active:translate-y-[1px] disabled:cursor-not-allowed disabled:opacity-60 disabled:hover:bg-[var(--color-magenta)]"
297					>
298						{submitting ? "Starting…" : "Generate video"}
299						{submitting ? null : <ArrowRightIcon />}
300					</button>
301					<span className="mono text-[11px] text-[var(--color-text-muted)]">
302						Estimated 45–60s · Powered by Gemini + Gradium
303					</span>
304				</div>
305			</form>
306		);
307	}
308	
309	export default SourceForm;
