	--color-magenta-bg: rgba(229, 38, 124, 0.08);
	--color-green: #2d6a4f;
	--color-amber: #8b6b1f;
	--color-red: #7a2e2e;

	--color-background: var(--color-bg);
	--color-foreground: var(--color-text);
	--color-ring: var(--color-magenta);
}

/* Permanent-dark theme: override shadcn vars to design tokens in both :root
   and .dark so the app renders identically regardless of theme class. */
