				>
					Voiceover failed — {error}.{" "}
					<button
						type="button"
						onClick={generate}
						className="underline transition-colors hover:text-[var(--color-text)]"
					>
						Retry
					</button>
				</div>
			) : (
				<div className="mono text-[11px] text-[var(--color-text-muted)]">
					Powered by Gradium
				</div>
			)}
		</div>
	);
}

